import { DEFAULT_SETTINGS } from '@sudoku/constants';
import { writable } from 'svelte/store';

function validateSettings(parsed) {
	if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
		return null;
	}
	const validated = {};
	for (const key of Object.keys(DEFAULT_SETTINGS)) {
		if (key in parsed && typeof parsed[key] === typeof DEFAULT_SETTINGS[key]) {
			validated[key] = parsed[key];
		} else {
			validated[key] = DEFAULT_SETTINGS[key];
		}
	}
	return validated;
}

function createSettings() {
	const settings = writable((() => {
		try {
			const storedSettings = localStorage.getItem('settings');
			if (storedSettings) {
				const parsed = JSON.parse(storedSettings);
				const validated = validateSettings(parsed);
				if (validated) return validated;
			}
		} catch (e) {
			// Corrupted localStorage data — fall back to defaults
		}

		return DEFAULT_SETTINGS;
	})());

	return {
		subscribe: settings.subscribe,

		set(newSettings) {
			settings.set(newSettings);
			localStorage.setItem('settings', JSON.stringify(newSettings));
		},
	};
}

export const settings = createSettings();
